/**
 * Build a FULL index of ALL manufacturerNames and productIds from driver.compose.json files.
 * Unlike buildIndex() in other scripts, this captures ALL entries, not just _T* and TS* patterns.
 * Returns {mfrIdx: Map<string,string[]>, pidIdx: Map<string,string[]>, allMfrs: Set, allPids: Set}
 */
function buildFullIndex(driversDir) {
  driversDir = driversDir || path.join(__dirname, '..', '..', 'drivers');
  const mfrIdx = new Map(), pidIdx = new Map();
  const allMfrs = new Set(), allPids = new Set();
  if (!fs.existsSync(driversDir)) return { mfrIdx, pidIdx, allMfrs, allPids };
  for (const d of fs.readdirSync(driversDir)) {
    const f = path.join(driversDir, d, 'driver.compose.json');
    if (!fs.existsSync(f)) continue;
    try {
      const data = JSON.parse(fs.readFileSync(f, 'utf8'));
      for (const m of (data.zigbee?.manufacturerName || [])) {
        allMfrs.add(m);
        if (!mfrIdx.has(m)) mfrIdx.set(m, []);
        if (!mfrIdx.get(m).includes(d)) mfrIdx.get(m).push(d);
      }
      for (const p of (data.zigbee?.productId || [])) {
        allPids.add(p);
        if (!pidIdx.has(p)) pidIdx.set(p, []);
        if (!pidIdx.get(p).includes(d)) pidIdx.get(p).push(d);
      }
    } catch {}
  }
  return { mfrIdx, pidIdx, allMfrs, allPids };
}

/**
 * Extract ALL fingerprints from text — Tuya _T*, TS####, AND known non-Tuya patterns.
 * Uses the full index to match any known manufacturerName or productId found in text.
 * @param {string} text - raw text to scan
 * @param {Set} [allMfrs] - optional set of all known manufacturerNames from buildFullIndex
 * @param {Set} [allPids] - optional set of all known productIds from buildFullIndex
 */
function extractAllFP(text, allMfrs, allPids) {
  const mfr = _vFP(text);
  // v5.12.16: Also capture TS#### with underscore suffixes (TS0601_generic, TS0601_air_purifier etc.)
  const pidRaw = (text || '').match(/\bTS[0-9]{4}[A-Z]?(?:_[a-zA-Z0-9]+)?\b/g) || [];
  const pid = [...new Set(pidRaw)];
  // Check for known non-Tuya manufacturers in text
  for (const k of NON_TUYA_KNOWN) {
    if (text && text.includes(k) && !mfr.includes(k)) mfr.push(k);
  }
  // Check for known non-TS productIds
  for (const p of NON_TS_PIDS) {
    if (text && text.includes(p) && !pid.includes(p)) pid.push(p);
  }
  // If full index provided, also scan for any exact match of known mfrs/pids
  // v5.12.16: Use case-insensitive matching so _tze200_abc matches _TZE200_ABC in DB
  if (allMfrs) {
    const textLower = (text || '').toLowerCase();
    for (const m of allMfrs) {
      if (m.length >= 4 && text && (text.includes(m) || textLower.includes(m.toLowerCase())) && !mfr.includes(m)) mfr.push(m);
    }
  }
  if (allPids) {
    const textLower2 = (text || '').toLowerCase();
    for (const p of allPids) {
      if (p.length >= 4 && text && (text.includes(p) || textLower2.includes(p.toLowerCase())) && !pid.includes(p)) pid.push(p);
    }
  }
  // Fuzzy match: find truncated FPs (e.g. _TZ3000_zgyzgd -> _TZ3000_zgyzgdua)
  if (allMfrs && allMfrs.size) {
    const fuzzy = fuzzyMatchFPs(mfr, allMfrs);
    for (const {original, match} of fuzzy) {
      if (!mfr.includes(match)) { mfr.push(match); mfr._fuzzy = mfr._fuzzy || {}; mfr._fuzzy[match] = original; }
    }
  }
  return { mfr, pid };
}

/**
 * Fuzzy match: for each extracted FP, if it's NOT in the known set,
 * check if it's a prefix of exactly one known FP (truncated in forum text).
 * Returns [{original, match}] pairs.
 */
function fuzzyMatchFPs(extractedFPs, knownSet) {
  const results = [];
  // v5.12.16: Lowered minimum from 10 to 8 to catch truncated _TZE200_XXX strings
  const known = [...knownSet].filter(k => k.length >= 8);
  for (const fp of extractedFPs) {
    if (knownSet.has(fp)) continue;
    if (fp.length < 8) continue;

    // Ignore suspicious concatenations (e.g. _TZ3000_zutizvykts0203)
    const fpL = fp.toLowerCase();
    if (fpL.includes('ts0') && fp.length > 18) continue;
    if (/ts\d{4}/i.test(fpL.slice(-6))) continue;
    if ((fp.match(/_/g)||[]).length > 2) continue;

    // 0. v5.12.16: Prefix-only match — user posted just the prefix like _TZE200_ (no suffix)
    //    Match to ALL known FPs that share that prefix (report all, caller picks)
    const prefixParts = fp.split('_');
    if (prefixParts.length >= 2 && prefixParts[2] === '') {
      const prefixKey = '_' + prefixParts[1] + '_';
      const prefixMatches = known.filter(k => k.toLowerCase().startsWith(prefixKey.toLowerCase()));
      for (const m of prefixMatches) {
        if (!results.some(r => r.match === m)) results.push({original: fp, match: m});
      }
      if (results.length) continue;
    }

    // 1. Prefix match: FP is start of a known FP (truncated in forum text)
    // v5.12.16: Increased tolerance from 4 to 8 chars for common truncations
    const prefixCands = known.filter(k => k.startsWith(fp) && k.length - fp.length <= 8);
    if (prefixCands.length === 1) { results.push({original: fp, match: prefixCands[0]}); continue; }
    if (prefixCands.length > 1 && prefixCands.length <= 5) {
      // Multiple prefix matches — add all as fuzzy candidates
      for (const m of prefixCands) {
        if (!results.some(r => r.match === m)) results.push({original: fp, match: m});
      }
      continue;
    }
    // 2. Reverse prefix: known is start of extracted (extra chars appended)
    const revCands = known.filter(k => fp.startsWith(k) && fp.length - k.length <= 8);
    if (revCands.length === 1) { results.push({original: fp, match: revCands[0]}); continue; }
    // 3. Same-length 1-char diff (typo/swap at end): _TZ3000_cehuw1l2 vs _TZ3000_cehuw1lw
    if (fp.length >= 12) {
      const prefix = fp.substring(0, fp.length - 2);
      const samePrefixCands = known.filter(k => k.length === fp.length && k.startsWith(prefix));
      if (samePrefixCands.length === 1) { results.push({original: fp, match: samePrefixCands[0]}); continue; }
      // Also try with 1-char shorter prefix for transpositions
      const prefix2 = fp.substring(0, fp.length - 3);
      const transpCands = known.filter(k => Math.abs(k.length - fp.length) <= 1 && k.startsWith(prefix2));
      if (transpCands.length === 1 && !results.some(r => r.match === transpCands[0])) {
        results.push({original: fp, match: transpCands[0]});
      }
    }
  }
  return results;
}


function resolveFingerprint(mfr, pid, dir) {
  dir = dir || path.join(__dirname, '..', '..', 'drivers');
  if (!mfr || !pid) return findDriver(mfr || pid);
  const ml = mfr.toLowerCase(), pl = pid.toLowerCase();
  for (const d of fs.readdirSync(dir)) {
    const f2 = path.join(dir, d, 'driver.compose.json');
    if (!fs.existsSync(f2)) continue;
    try {
      const data = JSON.parse(fs.readFileSync(f2, 'utf8'));
      const ms = (data.zigbee?.manufacturerName || []).map(s => s.toLowerCase());
      const ps = (data.zigbee?.productId || []).map(s => s.toLowerCase());
      if (ms.includes(ml) && ps.includes(pl)) return d;
    } catch {}
  }
  return null;
}

function getMultiDriverContext(dir) {
  dir = dir || path.join(__dirname, '..', '..', 'drivers');
  const { mfrIdx } = buildFullIndex(dir);
  const multi = [];
  for (const [mfr, drivers] of mfrIdx) {
    if (drivers.length > 1) multi.push({ mfr, drivers });
  }
  return multi;
}

module.exports = { loadFingerprints, findDriver, findAllDrivers, extractMfrFromText, buildFullIndex, extractAllFP, fuzzyMatchFPs, NON_TUYA_KNOWN, NON_TS_PIDS, resolveFingerprint, getMultiDriverContext };
